// src/bench.zig — Performance benchmarks for Omni-Mind.
//
// Runs a suite of queries and measures:
//   - End-to-end latency (ms)
//   - Memory usage (MB)
//   - Confidence score distribution
//   - Throughput (queries/sec)
//
// Compares results against theoretical GPT-4 baselines.

const std = @import("std");
const core = @import("core.zig");
