const log = std.log;

/// A benchmark question with expected properties.
pub const BenchQuestion = struct {
    id: u32,
    query: []const u8,
    expected_domain: u8, // 0xFF = any
    min_confidence: f32, // expected minimum confidence
    category: []const u8,
};

